    public List<BatchCarrierAssignedEventResponse> getBatchCarrierAssignedEvents(
            TransactionReceipt transactionReceipt) {
        List<Contract.EventValuesWithLog> valueList = extractEventParametersWithLog(BATCHCARRIERASSIGNED_EVENT, transactionReceipt);
        ArrayList<BatchCarrierAssignedEventResponse> responses = new ArrayList<BatchCarrierAssignedEventResponse>(valueList.size());
        for (Contract.EventValuesWithLog eventValues : valueList) {
            BatchCarrierAssignedEventResponse typedResponse = new BatchCarrierAssignedEventResponse();
            typedResponse.log = eventValues.getLog();
            typedResponse.operator = (String) eventValues.getIndexedValues().get(0).getValue();
            typedResponse.count = (BigInteger) eventValues.getNonIndexedValues().get(0).getValue();
            typedResponse.timestamp = (BigInteger) eventValues.getNonIndexedValues().get(1).getValue();
            responses.add(typedResponse);
        }
        return responses;
    }

